mapper.select:
SELECT 
FROM vso_delivery_appointment t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_id = #{orderId}


    AND t.appointment_status = #{appointmentStatus}


    AND t.delivery_mode = #{deliveryMode}

ORDER BY t.id DESC

